$fatpacked{"apps/vmware/vsphere8/esx/mode/discovery.pm"} = '#line '.(1+__LINE__).' "'.__FILE__."\"\n".<<'APPS_VMWARE_VSPHERE8_ESX_MODE_DISCOVERY';
  #
  # Copyright 2025 Centreon (http://www.centreon.com/)
  #
  # Centreon is a full-fledged industry-strength solution that meets
  # the needs in IT infrastructure and application monitoring for
  # service performance.
  #
  # Licensed under the Apache License, Version 2.0 (the "License");
  # you may not use this file except in compliance with the License.
  # You may obtain a copy of the License at
  #
  #     http://www.apache.org/licenses/LICENSE-2.0
  #
  # Unless required by applicable law or agreed to in writing, software
  # distributed under the License is distributed on an "AS IS" BASIS,
  # WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.
  # See the License for the specific language governing permissions and
  # limitations under the License.
  #
  
  package apps::vmware::vsphere8::esx::mode::discovery;
  
  use base qw(centreon::plugins::mode);
  
  use strict;
  use warnings;
  use JSON::XS;
  
  sub new {
      my ($class, %options) = @_;
      my $self = $class->SUPER::new(package => __PACKAGE__, %options);
      bless $self, $class;
      
      $options{options}->add_options(arguments => {
          'prettify'        => { name => 'prettify' }
      });
  
      return $self;
  }
  
  sub check_options {
      my ($self, %options) = @_;
      $self->SUPER::init(%options);
  }
  
  sub run {
      my ($self, %options) = @_;
  
      my $disco_stats;
      $disco_stats->{start_time} = time();
  
      # Retrieve the data
      my $response = $options{custom}->request_api('endpoint' => '/vcenter/host', 'method' => 'GET');
  
      # Format the data for host discovery
      my @results = map {
          'host_name' => $_->{name},
          'vmw_host_id' => $_->{host},
          'power_state' => $_->{power_state},
          'connection_state' => $_->{connection_state},
      }, @{$response};
  
      # Record the metadata
      $disco_stats->{end_time} = time();
      $disco_stats->{duration} = $disco_stats->{end_time} - $disco_stats->{start_time};
      $disco_stats->{discovered_items} = scalar(@results);
      $disco_stats->{results} = \@results;
  
      my $encoded_data;
      eval {
          if (defined($self->{option_results}->{prettify})) {
              $encoded_data = JSON::XS->new->utf8->canonical(1)->pretty->encode($disco_stats);
          } else {
              $encoded_data = JSON::XS->new->utf8->canonical(1)->encode($disco_stats);
          }
      };
      if ($@) {
          $encoded_data = '{"code":"encode_error","message":"Cannot encode discovered data into JSON format"}';
      }
  
      $self->{output}->output_add(short_msg => $encoded_data);
      $self->{output}->display(nolabel => 1, force_ignore_perfdata => 1);
  }
  
  1;
  
  
  =head1 MODE
  
  Resources discovery.
  
  =over 8
  
  =item B<--prettify>
  
  Prettify JSON output.
  
  =back
  
  =cut
APPS_VMWARE_VSPHERE8_ESX_MODE_DISCOVERY

$fatpacked{"apps/vmware/vsphere8/esx/mode/diskio.pm"} = '#line '.(1+__LINE__).' "'.__FILE__."\"\n".<<'APPS_VMWARE_VSPHERE8_ESX_MODE_DISKIO';
